INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (1, 'instagram', '2025-12-03', 'Reel', NULL, 'Posted', 'https://www.instagram.com/reel/DRzN1kGE9BO/?igsh=Z2g0ZTNqaDU1ZWNr', '17:30', 'Hey gorgeous people, Fine lines got you worried? Don''t fret! I''ve got some top tips to keep those pesky lines at bay! Daily sunscreen use, topical retinoids, and treatments like microneedling RF can work wonders Start your glow-up journey today and age like fine wine. #AgingGracefully #FineLines #SkincareTips #GlowUp', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'migration');
INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (1, 'instagram', '2025-12-05', 'Reel', NULL, 'Posted', 'https://www.instagram.com/reel/DR4cz0fEwtD/?igsh=aWY4c2Jnc29ocGxj', '18:30', 'Unlock the power of collagen! Microneedling, either alone or with radiofrequency, is a game-changer for boosting collagen production and strengthening your skin''s dermis. Pair it with red light therapy for an extra glow-up! And don''t forget to nourish from within with collagen supplements. Share your favorite skin rejuvenation tips with me! #Microneedling #CollagenBoost #SkinCare', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'migration');
INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (1, 'instagram', '2025-12-09', 'Reel', NULL, 'Posted', 'https://www.instagram.com/reel/DSCamIdk5un/?igsh=MXJnb2did3V4YjlweQ==', '15:00', 'Skin-deep secrets! 🤫 Your dermis is where the magic happens – collagen, elastin, and all! But let''s get real, topical creams can only do so much. 💁‍♀️ Procedures like microneedling, low-level laser therapy, and retinoids are where it''s at! Don''t fall for ''body firming'' hype – it''s all about prevention, not creation. Want to know the truth about firming up your skin? Consult a derm! #SkinCare #Collagen #Dermis #FirmingMyths', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'migration');
INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (1, 'instagram', '2025-12-12', 'Reel', NULL, 'Posted', 'https://www.instagram.com/reel/DSKTB_WiAzH/?utm_source=ig_web_copy_link&igsh=MzRlODBiNWFlZA==', '16:30', 'STOP scrolling! 🚨 Don''t DIY your skin tightening! At-home microneedling and red light therapy sounds cool, but trust me, it''s NOT worth the risk! Especially on your body, it can lead to irreversible hyperpigmentation and marks. 0.5mm microneedling? Might as well be scratching your skin for all the good it''ll do! Deep microneedling needs expertise, people! 👩‍⚕️ That''s why it''s best done under a derm''s supervision, in a derm''s clinic 📍#SkinCareWarnings #MicroneedlingRisks #DermatologistApproved', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'migration');
INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (1, 'instagram', '2025-12-16', 'Reel', NULL, 'Posted', 'https://www.instagram.com/reel/DSUSyibE08m/?igsh=MTFkbnIzaWlkbnJlbQ==', '13:43', 'Minoxidil myths vs facts! 🤔 Worried about side effects? Breathe easy! Topical minoxidil is pretty safe, with minimal risks 🚨. Transient headache, initial shedding, or rare allergic reactions are the most you''ll experience. Plus, it''s safe for both men and women, and won''t mess with your hormones! If you''re hesitant, you''re not alone!#MinoxidilMyths #HairLossSolutions #LowRiskTreatment #HairGrowth', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'migration');
INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (1, 'instagram', '2025-12-19', 'Reel', NULL, 'Posted', 'https://www.instagram.com/reel/DScNCHTkyt2/?igsh=bXBlejlnM2dkanN5', '15:28', 'Say goodbye to dark elbows! 👋 Here are my top tips to brighten and soften them up: 1️⃣ Gentle chemical exfoliation with lactic acid or urea 2️⃣ Daily moisturize with shea butter or ceramides 3️⃣ Brighten with kojic acid, niacinamide, or glycolic acid (Q-switch laser for the win! ) #DarkElbow #SkinCareTips #GlowUp', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'migration');
INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (1, 'instagram', '2025-12-23', 'Reel', NULL, 'Posted', 'https://www.instagram.com/reel/DSmNnvykwOT/?igsh=Y2h2eXpvdTlscnhk', '12:44', 'Ever wondered why your elbows are darker and rougher? 🤔It''s not dirt, it''s just your skin doing its thing! Constant friction and rubbing cause dead skin buildup, thickening, and darkening. Plus, elbows have fewer oil glands, making them prone to dryness. But here''s the thing: scrubbing harder isn''t the answer! 🚫 It can actually make it worse. Gentle care is key #ElbowCare #skinCare #healthyskin', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'migration');
INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (1, 'instagram', '2025-12-27', 'Reel', NULL, 'Posted', 'https://www.instagram.com/reel/DSwTMuXEzKH/?igsh=d2dpc2w1djZ0Z2c1', '11:30', '3 Tips to Prevent Early Skin Aging: 1️⃣ Retinoids: Prescription retinoids stimulate collagen, remove dead skin cells, and improve skin texture over time. 2️⃣ Daily Sunscreen: Consistent use prevents collagen breakdown and premature aging. Make it a habit! 3️⃣ Moisturizer: A strong skin barrier keeps skin plump, hydrated, and reduces fine lines. Consult your dermatologist before starting active ingredients like retinoids. #SkinCare #AntiAging #DermatologistTips', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'migration');
INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (1, 'instagram', '2025-12-28', 'Reel', NULL, 'Posted', 'https://www.instagram.com/reel/DSxI-IiE-wc/?igsh=OXAwaDVjYXExd3hm', '16:30', 'Think twice before using natural remedies on your skin! 🌟 Some ingredients, like besan, tomato pulp, and aloe vera gel, can do more harm than good. Consult a dermatologist before trying new skincare remedies. #SkinCare #NaturalRemedies #DermatologistApproved', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'migration');
INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (1, 'instagram', '2025-12-30', 'Reel', NULL, 'Posted', 'https://www.instagram.com/reel/DS5IjxNk0Np/?igsh=N21kNm9oajRjamNw', '18:30', 'Rocking a beard? 💈 Keep it classy! Cleanse under your beard regularly, moisturize the hair (not the skin!), and avoid heavy styling products. Comb and wash regularly to prevent folliculitis, psoriasis, and eczema. A clean beard is a healthy beard! Consult a dermatologist for personalized beard care tips. #BeardCare #SkinCare #DermatologistTips', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'migration');
INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (1, 'instagram', '2026-01-01', 'Reel', NULL, 'Posted', 'https://www.instagram.com/reel/DTDWLQDE6pZ/?igsh=aTBsNWQ2ZTIwNjRn', '18:30', 'Most tampons are safe when used correctly — whether cotton, organic, applicator, or non-applicator. The only type you should avoid is scented tampons, as they can irritate, disturb your pH, and increase infection risk.The main danger with any tampon is Toxic Shock Syndrome (TSS), which happens only if a tampon is worn for too long. Stay safe: * Choose the lowest absorbency * Change every 4–6 hours * Avoid wearing one overnight * Keep hands clean during insertion. Safest overall: Unscented organic cotton tampons. #TamponSafety #OrganicCotton #WomenHealth #skincare', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'migration');
INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (1, 'instagram', '2026-01-03', 'Reel', NULL, 'Posted', 'https://www.instagram.com/reel/DTDJeCeE-VQ/?igsh=MWNtNWdwajlwMDIzcg==', '18:30', 'Skincare staples or deal-breakers? Let''s break it down: Boroline: Great for occlusive moisture, but can trigger pimples Emoline: Budget-friendly, but contains propylene glycol, which may increase sensitivity Vaseline: Pure petrolatum jelly, perfect for sealing in moisture, but doesn''t hydrate on its own Know your skin type and choose wisely! Consult a dermatologist for personalized skincare advice. #skincare #moisturizer', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'migration');
INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (1, 'instagram', '2026-01-07', 'Reel', NULL, 'Posted', 'https://www.instagram.com/reel/DTMvr4EE4mK/?igsh=MWhlbjQ0dzFkZnN4Yg==', '11:53', 'When coloring your hair, prioritize caution! Hair colors contain peroxide, which can damage cuticles and cause dryness. To minimize risks, wear gloves, avoid coloring with scalp inflammation or severe dandruff, and apply Vaseline on your hairline. Choose PPD-free, dermatologist-recommended hair color and follow instructions carefully. Consult a dermatologist for personalized hair care advice. #haircare #haircolor #dermatologist', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'migration');
INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (1, 'instagram', '2026-01-09', 'Static', NULL, 'Posted', 'https://www.instagram.com/p/DTRxY_JEzQs/?utm_source=ig_web_copy_link&igsh=MzRlODBiNWFlZA==', '10:45', 'Dr. Divya Sharma''s post debunks the myth of repairing split ends, stating trimming is essential while conditioners merely support cuticle health without mending damage. Scientific evidence, including biomechanical analyses from sources like PubMed Central, confirms split ends cause irreversible structural weakening in hair shafts, with no peer-reviewed studies supporting permanent repair by masks or serums. As a Bangalore-based cosmetic dermatologist, Sharma frequently shares practical, myth-busting hair care tips on X, emphasizing evidence over influencer-driven product claims. #splitends #haircareroutine', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'migration');
INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (1, 'instagram', '2026-01-12', 'Reel', NULL, 'Posted', 'https://www.instagram.com/reel/DTaCp4iiCg_/?igsh=cDVuZnhrMDEwN2Zv', '15:48', 'Hair treatment vibes 💇‍♀️✨ Rating of these treatments are in comparison to other treatments! From Keratin to Clip-ons, know what''s worth your time (and money) 😉 DM us your fav hair treatment! 👉#HairCare #HairTreatments #HairGoals #HairAdvice', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'migration');
INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (1, 'instagram', '2026-01-14', 'Reel', NULL, 'Posted', 'https://www.instagram.com/reel/DTetlaWCKeB/?igsh=eGpmbHo1dW94bXYy', '11:30', 'Shaving hacks that are actually skin disasters 😬! Dry shaving or shaving against the grain can lead to nicks, razor burn, and dark spots ! And please don’t rub harsh scrubs or undiluted lemon on freshly shaved skin - ouch! 🍋Save your skin, sis! What’s your go-to shaving hack? 👉 Share with us! #ShavingTips #skin #hairremoval #skincare #selfcare', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'migration');
INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (1, 'instagram', '2026-01-17', 'Reel', NULL, 'Posted', 'https://www.instagram.com/reel/DTmXk5JE0f8/?igsh=MWdwN3VpM3RuN21icA==', '10:42', 'Noticing thinning hair, especially in the central part of your head (that christmas tree pattern)?  😬 It might be Female Pattern Hair Loss! 💁‍♀️ This needs more than just oils, shampoos, and home remedies. Consider consulting a dermatologist for tailored treatments like topical minoxidil, mesotherapy, LED lights, GFC, PRP injections, or exosomes. Early treatment is key! 👉 DM us to learn more about your options! #HairLossHelp #femalepatternhairloss #haircare #hairthinning #hairtreatment', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'migration');
INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (1, 'instagram', '2026-01-21', 'Reel', NULL, 'Posted', 'https://www.instagram.com/reel/DTxjyTyExl_/?igsh=MWdiYTZ6ZDFraXU3NA==', '19:01', 'DIY acne treatments can lead to irritation, inflammation, and scarring 😬. Picked acne lesions increase the risk of permanent marks. Consult a dermatologist for a scientific approach. Over-the-counter products and parlour treatments can worsen acne. Don’t risk your skin - seek expert help today! 👉  DM us to book a consultation #acnehelp #skincare #dermatologist', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'migration');
INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (1, 'instagram', '2026-01-25', 'Reel', NULL, 'Posted', 'https://www.instagram.com/reel/DUAMp9GiJMJ/?igsh=Y3V2ZXl4d2dzcXZs', '11:30', 'Don’t vent your stress on your skin! 😬 Squeezing or rubbing pimples can lead to black marks and more breakouts.  Keep your scalp and hairline clean, and avoid picking at those blackheads/whiteheads! 💁‍♀️ Consult a dermatologist to tackle the root cause. 👉 Share your skin struggles with us in the comments! #healthyskin acnetips #dermatologistadvice #skincare', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'migration');
INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (1, 'instagram', '2026-01-28', 'Reel', NULL, 'Posted', 'https://www.instagram.com/reel/DUFWw3pCIMX/?igsh=bHp5b21nMjhnNHhl', '11:30', 'Ditch the 5-blade razors! 😬 They’re causing those pesky ingrown hairs & strawberry legs 🍓👀 Switch to a single-blade razor for a smooth, clean cut. Shave with the grain, use a soap-free gel, and moisturize 💁‍♀️. Want baby skin legs? 👉 Check out my fav razors & post-shave creams in the comments! #shavingtips #smoothskin #dermatologistapproved #hairremoval', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'migration');
INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (1, 'instagram', '2026-01-30', 'Reel', NULL, 'Posted', 'https://www.instagram.com/reel/DULLdxlCHn8/?igsh=MTlnN2J0NXRlOTJlbA==', '17:50', 'Tubing mascara warning! 😬 Don’t skip the extra cleansing step or you might end up with permanent eye damage 💔. Use micellar water to gently remove it and protect your delicate skin. So, the bottom line is cleansing is the most underrated step in your skincare routine. Do it right to keep your eyes safe and your skin clear. 👉  Share your makeup removal tips with us! #makeupremoval #eyecare #dermaplaning #tubingmascara', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'migration');
INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (1, 'instagram', '2026-02-01', 'Reel', NULL, 'Posted', 'https://www.instagram.com/reel/DUPpA5_CGh_/?igsh=Mnpob3puYm1ybHll', '11:25', 'Acne scars ≠ open pores! 😬 Don’t waste your time and money on toners, serums, or medifacials. Collagen induction treatments like microneedling or CO2 laser are the way to go! 💡 Consult a dermatologist for a curated treatment plan. 👉 Share your skin concerns with us! #acnescars #skincare #dermatologistapproved #collageninductiontherapy', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'migration');
INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (1, 'instagram', '2026-02-03', 'Reel', NULL, 'Posted', 'https://www.instagram.com/reel/DUS1vOiiP1v/?igsh=ZThzdzQ1enh3bGZz', '17:15', 'Collagen creams aren’t the answer! 😬 As a dermatologist, I can tell you that retinoids, peptides, and Vitamin C are the real MVPs for boosting collagen production 💁‍♀️.Stimulate your skin from within, don’t just slap on collagen creams! 👉 Got questions about your serum? Drop a ‘yes’ in the comments! #antiaging #skincare #dermatologisttips #collagenproduction', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'migration');
INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (1, 'instagram', '2026-02-05', 'Reel', NULL, 'Posted', 'https://www.instagram.com/reel/DUak_NSCJ8C/?igsh=M2J4dDk0MG5oc3B1', '17:30', 'Skin care secrets revealed! 🚨 From what works to what doesn’t, let’s spill the tea! 💁‍♀️ Dermal fillers aren’t everything, know what really works for your skin 🤔 Double cleansing can trigger acne 💔
Ice cubes can cause burns & pigmentation ❌
Aloe vera gel? Only for hands & feet, not face! 🤚
Tea tree oil for oily skin & pimple backs 💆
Hydrocolloid patches for short-term pimple fix ⏱️
Comedone extractors under derm supervision only 🧑‍⚕️
Chemical peels & isotretinoin = 10/10 under derms 💯
Salicylic acid face wash for oily skin, but beware! ⚠️
Clay masks are just feel-good 😌
Coconut oil on face = big no-no 🚫
