INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (1, 'instagram', '2026-03-26', 'Reel', NULL, 'Posted', 'https://www.instagram.com/reel/DWVoDskiMuQ/?igsh=YTFlbmY4aWticTEw', '12:17', 'That “harmless mole” on your skin? It might not always be harmless. This is a real case where a patient noticed sudden changes in a mole — increase in size, uneven shape — and got it checked just in time. It turned out to be early-stage melanoma, a serious form of skin cancer. 
🚨 Watch out for the ABCDE warning signs:
* A – Asymmetry
* B – Border irregularity
* C – Color changes
* D – Diameter increase
* E – Evolving (size, shape, sensation) Early detection can save your life. Dermatologists use advanced tools like dermoscopy and may suggest a biopsy if needed. Don’t ignore changes in your skin — what seems small today can become serious tomorrow. 👉 Save this reel & share it with someone who needs to see this
💬 Comment “CHECK” if you want a quick self-examination guide for moles.
#skincancerawareness #melanoma #molecheck #dermatology #earlydetection', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'migration');
