INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (1, 'instagram', '2026-04-10', 'Reel', NULL, 'Posted', 'https://www.instagram.com/reel/DW8WM95E8zW/?igsh=d3g5NGhxMXliN3Q4', '13:05', 'Stop extracting your blackheads, whiteheads, and pimples at parlors 🚫

