INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (1, 'instagram', '2026-04-14', 'Reel', NULL, 'Posted', 'https://www.instagram.com/reel/DXGrrfUk_UL/?igsh=MTJxOXZtY2s0MzB2cA==', NULL, 'Hair fall solutions everywhere… but what actually works?

