INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (1, 'instagram', '2026-05-05', 'Reel', 'Sunscreens and oily skins

STRATEGIES DEPLOYED: Shock Hook · Awareness Trigger · Contrast Example · Relatability Mirror

[0:00-0:03] HOOK (🔴 OPEN LOOP 1) रणनीति: Shock Hook 
जो सनस्क्रीन आप रोज़ लगा रहे हो — वही आपका face दोपहर तक oily कर रही है। और आपको पता भी नहीं।

[0:03-0:10] LOOP OPENER (🔴 OPEN LOOP 2 | 🔴 HOLD LOOP 1) रणनीति: Awareness Trigger 
ज़्यादातर SPF products dry skin के लिए बनी हैं। Heavy bases, thick formulas — क्योंकि वो majority की complaint थी। अगर आपकी skin oily है, तो आप literally किसी और की skin के लिए बना product अपने face पर लगा रहे हो। हर एक दिन।

[0:10-0:25] MIDDLE (🟢 CLOSE LOOP 1 | 🔴 OPEN LOOP 3) रणनीति: Contrast Example 
एक बंदा है जो pharmacy से कोई भी SPF उठा लेता है — 10 बजे तक greasy, reapply skip, और end में ज़्यादा sun damage। दूसरा बंदा एक gel formula use करता है जो skin पर feel ही नहीं होती — वो willingly reapply करता है। Same sun. Same summer. बस formula अलग था। और honestly वो फर्क सालों बाद face पर दिखता है।

[0:25-0:38] RESOLUTION (🟢 CLOSE LOOP 2 & 3 | 🔴 HOLD FINAL LOOP) रणनीति: Awareness Trigger payoff Dermatologists 
अब niacinamide-based chemical sunscreens recommend कर रहे हैं — zero residue, no white cast, sebum control भी। Lightweight इतनी कि लगाई है या नहीं पता नहीं चलता। और यही sign है कि वो actually काम कर रही है। आपको सनस्क्रीन से नफरत नहीं थी — आपको गलत सनस्क्रीन से नफरत थी।

[0:38-0:43] LOOP CLOSE (🟢 CLOSE ALL) रणनीति: Relatability Mirror 
वो greasy, pilling, photos में flashback वाला version — वो आपकी skin के लिए था ही नहीं। सही formula मिल जाए तो सनस्क्रीन लगाना बंद नहीं करते।

[0:43-0:45] CTA 
अगली skincare haul से पहले save करो — नीचे skin type drop करो, बताता हूँ exactly कौनसा formula तुम्हारे लिए है।

VISUAL NOTES:
0:00: Close-up — oily skin midday, blotting paper pulling grease
0:03: Pharmacy shelf — rows of thick SPF, someone grabbing randomly
0:10: Split screen — greasy face vs clean dewy skin, same time of day
0:25: Minimal product shot — gel sunscreen, clean texture on finger
0:38: Someone touching their face, surprised it feels like nothing''s there
